/* Prism Tiny — vendored syntax highlighting for code blocks in responses.
 * MIT license. Stripped to essential tokens: keywords, strings, comments, numbers.
 * Zero network requests. Applied via CSS only — no eval/dynamic code. */
(function(global){
  'use strict';
  const Prism = {
    languages: {
      javascript: {
        comment: [/\/\*[\s\S]*?\*\//,/\/\/.*/],
        string: [/"(?:\\.|[^"\\])*"/,/'(?:\\.|[^'\\])*'/,/`(?:\\.|[^`\\])*`/],
        keyword: /\b(?:const|let|var|function|class|return|if|else|for|while|do|switch|case|break|continue|new|this|typeof|instanceof|import|export|default|async|await|null|true|false|undefined)\b/,
        number: /\b\d+\.?\d*\b/,
        operator: /[=!<>+\-*/%&|^~?:]+/,
      },
      python: {
        comment: /#.*/,
        string: [/"""[\s\S]*?"""/,/'''[\s\S]*?'''/,/"[^"]*"/,/'[^']*'/],
        keyword: /\b(?:def|class|return|if|elif|else|for|while|import|from|as|with|try|except|finally|raise|pass|break|continue|not|and|or|in|is|None|True|False|lambda|yield)\b/,
        number: /\b\d+\.?\d*\b/,
      },
      json: {
        string: /"(?:\\.|[^"\\])*"/,
        number: /-?\d+\.?\d*(?:[eE][+-]?\d+)?/,
        keyword: /\b(?:true|false|null)\b/,
        punctuation: /[{}\[\],:]/,
      },
      sql: {
        comment: [/--.*/, /\/\*[\s\S]*?\*\//],
        string: /'(?:[^']|'')*'/,
        keyword: /\b(?:SELECT|FROM|WHERE|INSERT|UPDATE|DELETE|CREATE|TABLE|INDEX|JOIN|ON|AS|AND|OR|NOT|IN|LIKE|ORDER|BY|GROUP|HAVING|LIMIT|OFFSET|PRIMARY|KEY|FOREIGN|REFERENCES|NULL|DEFAULT|IF|EXISTS|INTO|VALUES|SET|DROP|ALTER|ADD|COLUMN|UNIQUE|VARCHAR|INTEGER|REAL|TEXT|BLOB)\b/i,
        number: /\b\d+\.?\d*\b/,
      },
      bash: {
        comment: /#.*/,
        string: [/"(?:\\.|[^"\\])*"/,/'[^']*'/],
        keyword: /\b(?:if|then|else|elif|fi|for|do|done|while|until|case|esac|function|return|exit|echo|cd|ls|rm|mv|cp|mkdir|grep|sed|awk|curl|wget|export|source|set|unset|local)\b/,
      },
    },
    tokenize(code, grammar) {
      let result = [code];
      for (const [type, patterns] of Object.entries(grammar)) {
        const list = Array.isArray(patterns) ? patterns : [patterns];
        for (const pattern of list) {
          result = result.flatMap(token => {
            if (typeof token !== 'string') return [token];
            const parts = [];
            let last = 0;
            const re = new RegExp(pattern.source || pattern, (pattern.flags || '') + 'g');
            let m;
            while ((m = re.exec(token)) !== null) {
              if (m.index > last) parts.push(token.slice(last, m.index));
              parts.push({ type, content: m[0] });
              last = m.index + m[0].length;
            }
            if (last < token.length) parts.push(token.slice(last));
            return parts;
          });
        }
      }
      return result;
    },
    highlight(code, grammar) {
      return this.tokenize(code, grammar).map(t => {
        if (typeof t === 'string') return t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        const content = t.content.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        return `<span class="token ${t.type}">${content}</span>`;
      }).join('');
    },
    highlightAll() {
      document.querySelectorAll('pre code[class*="language-"]').forEach(block => {
        const lang = (block.className.match(/language-(\w+)/) || [])[1] || '';
        const grammar = Prism.languages[lang];
        if (grammar) block.innerHTML = Prism.highlight(block.textContent, grammar);
      });
    },
  };
  global.Prism = Prism;
})(typeof window !== 'undefined' ? window : globalThis);
